  1→/**
  2→ * sequant doctor - Check installation health
  3→ */
  4→
  5→import chalk from "chalk";
  6→import { execSync } from "child_process";
  7→import { ui, colors } from "../lib/cli-ui.js";
  8→import { GitHubProvider } from "../lib/workflow/platforms/github.js";
  9→import { fileExists, isExecutable } from "../lib/fs.js";
 10→import { getManifest } from "../lib/manifest.js";
 11→import {
 12→  commandExists,
 13→  isGhAuthenticated,
 14→  isNativeWindows,
 15→  isWSL,
 16→  checkOptionalMcpServers,
 17→  getMcpServersConfig,
 18→  OPTIONAL_MCP_SERVERS,
 19→} from "../lib/system.js";
 20→import {
 21→  checkVersionThorough,
 22→  getVersionWarning,
 23→} from "../lib/version-check.js";
 24→import { areSkillsOutdated } from "./sync.js";
 25→import {
 26→  readAgentsMd,
 27→  checkAgentsMdConsistency,
 28→  AGENTS_MD_PATH,
 29→} from "../lib/agents-md.js";
 30→import { readFile } from "../lib/fs.js";
 31→
 32→interface Check {
 33→  name: string;
 34→  status: "pass" | "warn" | "fail";
 35→  message: string;
 36→  fix?: () => Promise<void>;
 37→}
 38→
 39→export interface DoctorOptions {
 40→  skipIssueCheck?: boolean;
 41→}
 42→
 43→/**
 44→ * Labels that indicate an issue should be skipped from closed-issue verification
 45→ * (case-insensitive matching)
 46→ */
 47→const SKIP_ISSUE_LABELS = [
 48→  "wontfix",
 49→  "won't fix",
 50→  "duplicate",
 51→  "invalid",
 52→  "question",
 53→  "documentation",
 54→  "docs",
 55→];
 56→
 57→interface ClosedIssue {
 58→  number: number;
 59→  title: string;
 60→  closedAt: string;
 61→  labels: Array<{ name: string }>;
 62→}
 63→
 64→/**
 65→ * Check recently closed issues for missing commits in main branch
 66→ * Returns issues that were closed but have no commit referencing them
 67→ */
 68→export function checkClosedIssues(): ClosedIssue[] {
 69→  const sevenDaysAgo = new Date();
 70→  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
 71→  const sevenDaysAgoISO = sevenDaysAgo.toISOString();
 72→
 73→  // Fetch closed issues from last 7 days
 74→  const github = new GitHubProvider();
 75→  const closedIssues = github.listClosedIssuesSync(100) as ClosedIssue[];
 76→
 77→  // Filter to last 7 days
 78→  const recentIssues = closedIssues.filter(
 79→    (issue) => issue.closedAt >= sevenDaysAgoISO,
 80→  );
 81→
 82→  // Filter out issues with skip labels
 83→  const issuesToCheck = recentIssues.filter((issue) => {
 84→    const labels = issue.labels.map((l) => l.name.toLowerCase());
 85→    return !SKIP_ISSUE_LABELS.some((skipLabel) =>
 86→      labels.some((label) => label.includes(skipLabel.toLowerCase())),
 87→    );
 88→  });
 89→
 90→  // Check each issue for a commit in main
 91→  const missingCommitIssues: ClosedIssue[] = [];
 92→  for (const issue of issuesToCheck) {
 93→    try {
 94→      // Look for commit mentioning this issue number
 95→      const result = execSync(
 96→        `git log --oneline --grep="#${issue.number}" -1`,
 97→        {
 98→          encoding: "utf-8",
 99→          stdio: ["pipe", "pipe", "pipe"],
100→        },
101→      );
102→      // If no output, no commit found
103→      if (!result.trim()) {
104→        missingCommitIssues.push(issue);
105→      }
106→    } catch {
107→      // git log failed or no match - treat as missing
108→      missingCommitIssues.push(issue);
109→    }
110→  }
111→
112→  return missingCommitIssues;
113→}
114→
115→export async function doctorCommand(
116→  options: DoctorOptions = {},
117→): Promise<void> {
118→  console.log(ui.headerBox("SEQUANT HEALTH CHECK"));
119→  console.log();
120→
121→  const checks: Check[] = [];
122→  // Track gh availability and auth for conditional checks later
123→  let ghAvailable = false;
124→  let ghAuthenticated = false;
125→
126→  // Check 0: Version freshness
127→  const versionResult = await checkVersionThorough();
128→  if (versionResult.latestVersion) {
129→    if (versionResult.isOutdated) {
130→      checks.push({
131→        name: "Version",
132→        status: "warn",
133→        message: `Outdated: ${versionResult.currentVersion} → ${versionResult.latestVersion} available`,
134→      });
135→      // Show remediation steps
136→      console.log(
137→        chalk.yellow(
138→          `  ⚠️  ${getVersionWarning(versionResult.currentVersion, versionResult.latestVersion, versionResult.isLocalInstall)}`,
139→        ),
140→      );
141→      console.log("");
142→    } else {
143→      checks.push({
144→        name: "Version",
145→        status: "pass",
146→        message: `Up to date (${versionResult.currentVersion})`,
147→      });
148→    }
149→  } else {
150→    // Could not fetch version - skip this check silently (graceful degradation)
151→    checks.push({
152→      name: "Version",
153→      status: "pass",
154→      message: `${versionResult.currentVersion} (could not verify latest)`,
155→    });
156→  }
157→
158→  // Check 1: Manifest exists
159→  const manifest = await getManifest();
160→  if (manifest) {
161→    checks.push({
162→      name: "Manifest",
163→      status: "pass",
164→      message: `Found .sequant-manifest.json (v${manifest.version})`,
165→    });
166→  } else {
167→    checks.push({
168→      name: "Manifest",
169→      status: "fail",
170→      message: "Missing .sequant-manifest.json - run `sequant init`",
171→    });
172→  }
173→
174→  // Check 2: Skills directory
175→  const skillsExist = await fileExists(".claude/skills");
176→  if (skillsExist) {
177→    checks.push({
178→      name: "Skills",
179→      status: "pass",
180→      message: "Skills directory exists",
181→    });
182→  } else {
183→    checks.push({
184→      name: "Skills",
185→      status: "fail",
186→      message: "Missing .claude/skills/ directory",
187→    });
188→  }
189→
190→  // Check 3: Core skills present
191→  const coreSkills = ["spec", "exec", "qa"];
192→  const missingSkills: string[] = [];
193→  for (const skill of coreSkills) {
194→    if (!(await fileExists(`.claude/skills/${skill}/SKILL.md`))) {
195→      missingSkills.push(skill);
196→    }
197→  }
198→  if (missingSkills.length === 0) {
199→    checks.push({
200→      name: "Core Skills",
201→      status: "pass",
202→      message: "All core skills present (spec, exec, qa)",
203→    });
204→  } else {
205→    checks.push({
206→      name: "Core Skills",
207→      status: "fail",
208→      message: `Missing skills: ${missingSkills.join(", ")}`,
209→    });
210→  }
211→
212→  // Check 3.5: Skills version (are skills in sync with package?)
213→  const skillsStatus = await areSkillsOutdated();
214→  if (skillsStatus.outdated) {
215→    checks.push({
216→      name: "Skills Version",
217→      status: "warn",
218→      message: `Outdated (${skillsStatus.currentVersion || "unknown"} → ${skillsStatus.packageVersion}) - run: npx sequant sync`,
219→    });
220→  } else {
221→    checks.push({
222→      name: "Skills Version",
223→      status: "pass",
224→      message: `Up to date (${skillsStatus.packageVersion})`,
225→    });
226→  }
227→
228→  // Check: AGENTS.md presence and consistency
229→  const agentsMdContent = await readAgentsMd();
230→  if (agentsMdContent) {
231→    // Check consistency with CLAUDE.md if both exist
232→    if (await fileExists("CLAUDE.md")) {
233→      try {
234→        const claudeMdContent = await readFile("CLAUDE.md");
235→        const inconsistency = checkAgentsMdConsistency(
236→          agentsMdContent,
237→          claudeMdContent,
238→        );
239→        if (inconsistency) {
240→          checks.push({
241→            name: "AGENTS.md",
242→            status: "warn",
243→            message: `Out of sync with CLAUDE.md: ${inconsistency}. Run: sequant sync --force`,
244→          });
245→        } else {
246→          checks.push({
247→            name: "AGENTS.md",
248→            status: "pass",
249→            message: "Present and consistent with CLAUDE.md",
250→          });
251→        }
252→      } catch {
253→        checks.push({
