    async () => {
      try {
        if (!fs.existsSync(STATE_FILE_PATH)) {
          return {
            contents: [
              {
                uri: "sequant://state",
                mimeType: "application/json",
                text: JSON.stringify({ issues: {} }),
              },
            ],
          };
